@page "/board"
@using sv_a07e06d5bdcd4f439394eb88ec4f2fed.Services
@inject ITaskService TaskService
@rendermode InteractiveServer

<PageTitle>Kanban Board</PageTitle>

<h2 class="mb-3">Project Board</h2>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (_error is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error:</strong> @_error
        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
    </div>
}
else
{
    @* ── Summary stats bar ── *@
    <div class="row g-2 mb-3">
        <div class="col"><div class="card text-center p-2"><strong>@_allTasks.Count</strong><br /><small class="text-muted">Total</small></div></div>
        @foreach (var col in Columns)
        {
            <div class="col">
                <div class="card text-center p-2">
                    <strong>@CountFor(col)</strong><br /><small class="text-muted">@col</small>
                </div>
            </div>
        }
        <div class="col">
            <div class="card text-center p-2 @(OverdueCount > 0 ? "border-danger" : "")">
                <strong class="@(OverdueCount > 0 ? "text-danger" : "")">@OverdueCount</strong><br /><small class="text-muted">Overdue</small>
            </div>
        </div>
    </div>

    @* ── Search bar ── *@
    <div class="mb-3">
        <input type="text" class="form-control" placeholder="Search tasks by title…"
               @bind="_searchQuery" @bind:event="oninput" />
    </div>

    @* ── Kanban columns ── *@
    <div class="row g-3">
        @for (var i = 0; i < Columns.Length; i++)
        {
            var colIndex = i;
            var column = Columns[colIndex];
            var tasks = FilteredTasksFor(column);

            <div class="col-md-4">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <span class="fw-bold">@column</span>
                        <span class="badge bg-secondary">@tasks.Count</span>
                    </div>
                    <div class="card-body d-flex flex-column gap-2 overflow-auto" style="min-height:200px;">
                        @foreach (var task in tasks)
                        {
                            <div class="card shadow-sm">
                                <div class="card-body p-2">
                                    <h6 class="card-title mb-1">@task.Title</h6>
                                    <p class="mb-1 text-muted small">@task.Assignee</p>
                                    <div class="d-flex justify-content-between align-items-center mb-1">
                                        <span class="badge @PriorityClass(task.Priority)">@task.Priority</span>
                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
                                    </div>
                                    <div class="d-flex gap-1">
                                        @if (colIndex > 0)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex - 1])">
                                                ← Move Left
                                            </button>
                                        }
                                        @if (colIndex < Columns.Length - 1)
                                        {
                                            <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                    disabled="@_moving"
                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex + 1])">
                                                Move Right →
                                            </button>
                                        }
                                    </div>
                                </div>
                            </div>
                        }

                        @* ── Inline add-task form ── *@
                        @if (_addingColumn == column)
                        {
                            <div class="card border-primary">
                                <div class="card-body p-2">
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Title" @bind="_newTitle" />
                                    <input type="text" class="form-control form-control-sm mb-1"
                                           placeholder="Assignee" @bind="_newAssignee" />
                                    <select class="form-select form-select-sm mb-1" @bind="_newPriority">
                                        <option value="High">High</option>
                                        <option value="Medium">Medium</option>
                                        <option value="Low">Low</option>
                                    </select>
                                    <input type="date" class="form-control form-control-sm mb-2" @bind="_newDueDate" />
                                    <div class="d-flex gap-1">
                                        <button class="btn btn-primary btn-sm flex-fill"
                                                disabled="@_saving"
                                                @onclick="() => SaveNewTaskAsync(column)">
                                            Save
                                        </button>
                                        <button class="btn btn-outline-secondary btn-sm flex-fill"
                                                @onclick="CancelAdd">
                                            Cancel
                                        </button>
                                    </div>
                                </div>
                            </div>
                        }
                    </div>
                    <div class="card-footer">
                        <button class="btn btn-outline-primary btn-sm w-100"
                                @onclick="() => BeginAdd(column)">
                            + Add Task
                        </button>
                    </div>
                </div>
            </div>
        }
    </div>
}

@code {
    private static readonly string[] Columns = ["To Do", "In Progress", "Done"];

    private List<TaskItem> _allTasks = new();
    private bool _loading = true;
    private string? _error;
    private string _searchQuery = string.Empty;
    private bool _moving;

    // Add-task form state
    private string? _addingColumn;
    private string _newTitle = string.Empty;
    private string _newAssignee = string.Empty;
    private string _newPriority = "Medium";
    private DateTime _newDueDate = DateTime.Today.AddDays(7);
    private bool _saving;

    protected override async Task OnInitializedAsync() => await LoadTasksAsync();

    private async Task LoadTasksAsync()
    {
        try
        {
            _loading = true;
            _error = null;
            _allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _loading = false;
        }
    }

    // ── Helpers ──

    private int CountFor(string status) => _allTasks.Count(t => t.Status == status);
    private int OverdueCount => _allTasks.Count(t => t.DueDate.Date < DateTime.Today);

    private List<TaskItem> FilteredTasksFor(string status)
    {
        IEnumerable<TaskItem> items = _allTasks.Where(t => t.Status == status);
        if (!string.IsNullOrWhiteSpace(_searchQuery))
            items = items.Where(t => t.Title.Contains(_searchQuery, StringComparison.OrdinalIgnoreCase));
        return items.ToList();
    }

    private static string PriorityClass(string priority) => priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };

    // ── Move task ──

    private async Task MoveTaskAsync(int taskId, string newStatus)
    {
        try
        {
            _moving = true;
            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
            var idx = _allTasks.FindIndex(t => t.Id == taskId);
            if (idx >= 0)
            {
                var old = _allTasks[idx];
                _allTasks[idx] = old with { Status = newStatus };
            }
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _moving = false;
        }
    }

    // ── Add task ──

    private void BeginAdd(string column)
    {
        _addingColumn = column;
        _newTitle = string.Empty;
        _newAssignee = string.Empty;
        _newPriority = "Medium";
        _newDueDate = DateTime.Today.AddDays(7);
    }

    private void CancelAdd() => _addingColumn = null;

    private async Task SaveNewTaskAsync(string column)
    {
        if (string.IsNullOrWhiteSpace(_newTitle)) return;
        try
        {
            _saving = true;
            var created = await TaskService.CreateTaskAsync(_newTitle, _newAssignee, _newPriority, _newDueDate);
            // The service may or may not set the status to the target column;
            // ensure the local copy matches the column it was added from.
            _allTasks.Add(created with { Status = column });
            _addingColumn = null;
        }
        catch (Exception ex)
        {
            _error = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }
}

